class Solution {
    public int leastOpsExpressTarget(int x, int target) {
        int ans = Integer.MAX_VALUE;
        for (int i = 1; i <= target; i *= x) {
            int ops = 0;
            int mul = i;
            int add = target - i;
            while (mul < add) {
                mul *= x;
                ops++;
            }
            while (mul > add) {
                mul /= x;
                ops++;
            }
            ans = Math.min(ans, ops + 1);
        }
        return ans;
    }
}
